const allItems = $input.all();
const insights = [];
let inQueueSection = false;

for (const item of allItems) {
  const response = item.json;
  const blocks = response.results || [];

  for (const block of blocks) {
    if (!block) continue;
    const blockType = block.type;
    const blockContent = block[blockType];

    // 1. Wyciagnij tekst (obsuga roznych struktur Notion API)
    let rawText = '';
    if (blockContent && blockContent.rich_text) {
      rawText = blockContent.rich_text.map(rt => rt.plain_text || rt.text?.content || '').join('').trim();
    }

    if (!rawText) continue;

    // 2. Logika sekcji
    if (blockType.startsWith('heading_') && rawText.toUpperCase().includes('QUEUE')) {
      inQueueSection = true;
      continue;
    }

    if (inQueueSection && blockType.startsWith('heading_')) {
      inQueueSection = false;
      continue;
    }

    // 3. Przetwarzaj tylko w sekcji QUEUE i tylko bullety
    if (inQueueSection && blockType === 'bulleted_list_item') {
      // Filtry statusu
      if (rawText.indexOf('[PUBLISHED') !== -1) continue;
      if (rawText.indexOf('[REJECTED') !== -1) continue;
      if (rawText.indexOf('[ARCHIVED') !== -1) continue;
      if (rawText.startsWith('//')) continue;

      var priority = 'normal';
      if (rawText.indexOf('[HIGH]') !== -1) priority = 'high';
      if (rawText.indexOf('[LOW]') !== -1) priority = 'low';

      var topic = 'General';
      var topicMatch = rawText.match(/\[([^\]]+)\]/g) || [];
      for (var t = 0; t < topicMatch.length; t++) {
        var inner = topicMatch[t].slice(1, -1).trim().toUpperCase();
        if (inner !== 'HIGH' && inner !== 'MED' && inner !== 'LOW' && inner !== 'MEDIUM') {
          topic = topicMatch[t].slice(1, -1).trim();
          break;
        }
      }

      // Czyszczenie tekstu z tagow [TAG]
      var cleanText = rawText.replace(/\[[^\]]*\]/g, '').replace(/\s+/g, ' ').trim();
      if (!cleanText) cleanText = rawText;

      insights.push({
        text: cleanText, // Mapowanie do text (KLUCZOWE)
        rawText: rawText,
        priority: priority,
        topic: topic,
        notionBlockId: block.id,
        status: 'queued',
        blockType: blockType
      });
    }
  }
}

// Sortowanie
insights.sort((a, b) => {
  const order = { high: 0, normal: 1, low: 2 };
  return (order[a.priority] || 1) - (order[b.priority] || 1);
});

if (insights.length === 0) {
  return [{ json: { isEmpty: true, message: 'Brak insightów w sekcji ## QUEUE', count: 0 } }];
}

return insights.map(i => ({ json: i }));

// Merge rate limit result with insight data
// $input.first() has the postgres result, we need the insight from earlier
const rateData = $input.first().json;
const postCount = parseInt(rateData.post_count || rateData[0]?.post_count || 0);

// Get insight from the batch item - look at all inputs
let insight = {};
for (const item of $input.all()) {
  if (item.json.text) {
    insight = item.json;
    break;
  }
}

return [{
  json: {
    ...insight,
    dailyPostCount: postCount,
    rateLimitReached: postCount >= 5
  }
}];

