// Extract draft text from Claude response
const response = $input.first().json;
const draft = response.content?.[0]?.text?.trim() || '';

// Get original insight from Split In Batches
const insightData = $('Split In Batches').first().json;

// Liczba pozostalych itemow w kolejce
const queueRemaining = $('Parse Queue Items').all().length - 1;

// GUARD: Jesli Claude zwrocil SKIP zamiast posta -- to blad promptu, nie decyzja
const REFUSAL = /i don'?t see|could you share|provide the insight|share the bullet|no insight (text|provided)|don'?t have (an?|any)? ?insight/i;
if (draft === 'SKIP_NO_INSIGHT' || draft === '' || REFUSAL.test(draft)) {
  return [{
    json: {
      ...insightData,
      draft: '',
      claudeError: true,
      queueRemaining: queueRemaining >= 0 ? queueRemaining : 0
    }
  }];
}

return [{
  json: {
    ...insightData,
    draft,
    claudeError: false,
    queueRemaining: queueRemaining >= 0 ? queueRemaining : 0,
    retryCount: $json.retryCount !== undefined ? $json.retryCount : 0,
    adaptationAttempt: ($json.retryCount || 0) + 1
  }
}];

// Parse brand canon check result
const response = $input.first().json;
const rawText = response.content?.[0]?.text?.trim() || '{}';

// Extract JSON from response (Claude may wrap it in markdown)
let canonResult = {};
try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    canonResult = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  canonResult = { pass: false, violations: ['parse_error'], em_dash_detected: false, char_count: 0 };
}

// Get draft data from previous context
const allItems = $input.all();
let draftData = {};
for (const item of allItems) {
  if (item.json.draft !== undefined) {
    draftData = item.json;
    break;
  }
}

// Force fail if em dash is detected in draft text
const draft = draftData.draft || '';
const emDashInDraft = draft.includes('\u2014') || draft.includes('\u2013');
if (emDashInDraft) {
  canonResult.pass = false;
  canonResult.em_dash_detected = true;
  if (!canonResult.violations) canonResult.violations = [];
  if (!canonResult.violations.includes('em_dash')) {
    canonResult.violations.unshift('em_dash');
  }
}

return [{
  json: {
    ...draftData,
    canonPass: canonResult.pass === true,
    canonViolations: canonResult.violations || [],
    emDashDetected: canonResult.em_dash_detected || emDashInDraft,
    charCount: canonResult.char_count || draft.length,
    retryCount: draftData.retryCount || 0
  }
}];

// Generate callback ID for HITL session tracking
const executionId = $execution.id || 'exec-' + Date.now();
const callbackId = executionId + '_hitl';

let draft = $json.draft || '';
let topic = $json.topic || 'General';
let priority = $json.priority || 'normal';
let notionBlockId = $json.notionBlockId || '';
let charCount = draft.length;
let queueRemaining = $json.queueRemaining || 0;

if (!draft) {
  try {
    const extractData = $('Extract Draft').first().json;
    draft = extractData.draft || '';
    topic = extractData.topic || topic;
    priority = extractData.priority || priority;
    notionBlockId = extractData.notionBlockId || notionBlockId;
    charCount = draft.length;
    queueRemaining = extractData.queueRemaining || 0;
  } catch(e) {}
}

const queueInfo = queueRemaining > 0
  ? 'Queue: ' + queueRemaining + ' remaining'
  : 'Queue: this is the last item';

const previewText = 'X DRAFT - ' + topic + '\n\n' + (draft || '[BRAK DRAFTU]') + '\n\nChars: ' + charCount + ' | ' + queueInfo + '\nApprove to publish.';

const tgBody = {
  chat_id: $json.telegramChatId || '2106351328',
  text: previewText,
  disable_web_page_preview: true,
  reply_markup: {
    inline_keyboard: [[
      { text: '\u2705 Approve', callback_data: callbackId + ':approve' },
      { text: '\u274c Reject', callback_data: callbackId + ':reject' },
      { text: '\u270f\ufe0f Edit', callback_data: callbackId + ':edit' }
    ], [
      { text: '\ud83d\udd50 Zaplanuj', callback_data: callbackId + ':schedule' }
    ]]
  }
};

return [{
  json: {
    ...$json,
    draft,
    topic,
    priority,
    notionBlockId,
    charCount,
    callbackId,
    executionId,
    resumeUrl: $execution.resumeUrl || '',
    tgBodyStr: JSON.stringify(tgBody)
  }
}];

// Extract error details for alert
const errorData = $input.first().json;
const errorMessage = errorData.execution?.error?.message || errorData.error?.message || 'Unknown error';
const workflowName = errorData.workflow?.name || 'AGS X Agent';
const nodeName = errorData.execution?.error?.node?.name || errorData.error?.node?.name || 'Unknown node';

return [{
  json: {
    errorMessage,
    workflowName,
    nodeName,
    errorData,
    alertText: `AGS X Agent ERROR\nNode: ${nodeName}\nError: ${errorMessage}`
  }
}];

// Prepare data for hitl_sessions INSERT
// Escape single quotes for SQL safety
const prev = $('Prepare HITL Preview').first().json;
const callbackId = prev.callbackId || '';
const executionId = prev.executionId || '';
const draft = (prev.draft || '').replace(/'/g, "''");  // SQL escape: ' -> ''
const notionBlockId = (prev.notionBlockId || '').replace(/'/g, "''");
const topic = (prev.topic || 'General').replace(/'/g, "''");
const priority = (prev.priority || 'normal').replace(/'/g, "''");

return [{ json: { callbackId, executionId, draft_esc: draft, notionBlockId_esc: notionBlockId, topic_esc: topic, priority_esc: priority } }];

// Agreguj ostatnie posty do listy
const recentPosts = $input.all().map(i => i.json.content).filter(c => c).join('\n---\n');
// Pobierz insight z Split In Batches
const insight = $('Split In Batches').first().json;

return [{
  json: {
    ...insight,
    recent_posts_list: recentPosts || 'No recent posts found.'
  }
}];

const item = $input.first().json;
const text = item.text || '';
if (!text || text === 'undefined' || text.length < 3) {
  return [{ json: { isValid: false, error: 'Empty input', notionBlockId: item.notionBlockId } }];
}
return [{ json: { ...item, isValid: true } }];

